export class TimeUtility {

  static getDuration(date1: Date, date2: Date): number {
    return Math.abs(date1.getTime() - date2.getTime())
  }

  static msToTime(millis: number): { h: string, m: string, s: string, ms: string } {
    let milliseconds = Math.floor((millis % 1000) / 100),
      seconds = Math.floor((millis / 1000) % 60),
      minutes = Math.floor((millis / (1000 * 60)) % 60),
      hours = Math.floor((millis / (1000 * 60 * 60)) % 24);

    let h = (hours < 10) ? "0" + hours : hours + "";
    let m = (minutes < 10) ? "0" + minutes : minutes + "";
    let s = (seconds < 10) ? "0" + seconds : seconds + "";

    return {
      h: h,
      m: m,
      s: s,
      ms: milliseconds + ""
    }
  }

  static msToReadableTime(millis: number, showSeconds: boolean): string {
    let t = this.msToTime(millis)
    if (t.h === '00' && t.m === '00') return 'just now'
    let time = ''
    if (t.h !== '00')
      time = t.h + ' h '
    time = time + '' + t.m + ' min'

    if (showSeconds) time = ' ' + time + ' sec'
    return time + ' ago'
  }

  static calculateRange(period: string): { fromDate: Date, toDate: Date } | null {
    switch (period) {
      case 'TODAY': {
        let date = new Date()
        return {fromDate: this.getDayStart(date), toDate: this.getDayEnd(date)}
      }
      case 'YESTERDAY': {
        let date = this.getDayBefore(new Date(), 1)
        return {fromDate: this.getDayStart(date), toDate: this.getDayEnd(date)}
      }
      case 'THIS_WEEK': {
        let earlierDate = this.getDayBefore(new Date(), 7)
        return {fromDate: this.getDayStart(earlierDate), toDate: this.getDayEnd(new Date())}
      }

      case 'THIS_MONTH': {
        let dates = this.getFirstAndLastDayOfMonth(new Date())
        return {fromDate: dates.firstDay, toDate: dates.lastDay}
      }

      case 'LAST_MONTH': {
        let date = new Date()
        date.setMonth(date.getMonth() - 1) // same day last month
        let dates = this.getFirstAndLastDayOfMonth(date)
        return {fromDate: dates.firstDay, toDate: dates.lastDay}
      }

    }

    return null
  }

  static getDayBefore(date: Date, days: number): Date {
    return new Date(date.getTime() - (days * 24 * 60 * 60 * 1000));
  }

  static getDayStart(date: Date): Date {
    date.setUTCHours(0, 0, 0, 0);
    return date
  }

  static getDayEnd(date: Date): Date {
    date.setUTCHours(23, 59, 59, 999);
    return date
  }

  static getFirstAndLastDayOfMonth(date: Date): { firstDay: Date, lastDay: Date } {
    const firstDay = new Date(date.getFullYear(), date.getMonth(), 1);
    const lastDay = new Date(date.getFullYear(), date.getMonth() + 1, 0);
    return {firstDay: this.getDayStart(firstDay), lastDay: this.getDayEnd(lastDay)}
  }

}
