import {Injectable} from '@angular/core';
import {environment} from "../../../environments/environment";
import {IParams} from "./iparams";

@Injectable({
  providedIn: 'root'
})
export class BaseEndpoint {

  constructor() {
  }

  static API_VERSION_1 = '/api/v1';
  static API_VERSION_2 = '/api/v2';

  static toParamString(params: IParams): string {
    let p: string = "";
    for (let key in params) {
      let value = params[key]
      if (value == null) continue
      if (p === '') p = p + '?'; else {
        p = p + '&';
      }
      p = p + key + '=' + this.convertToString(params[key])
    }
    return p
  }

  static convertToString(value: any){
    if (value instanceof Date)
      return value.toISOString()
    return value.toString()
  }

  static FILES = {
    UPLOAD(params: IParams): string {
      return environment.base_url + BaseEndpoint.API_VERSION_2 + '/images/bulk'
        .concat(BaseEndpoint.toParamString(params));
    },
    // SEARCH(params: Params) {
    //   return environment.base_url + BaseEndpoint.API_VERSION_1 + '/products'
    //     .concat(BaseEndpoint.toParamString(params));
    // },
    // FETCH_BY_ID(id: number) {
    //   return environment.base_url + BaseEndpoint.API_VERSION_1 + '/products/' + id;
    // },
    // CREATE(): string {
    //   return environment.base_url + BaseEndpoint.API_VERSION_1 + '/products';
    // },
    // UPDATE(id: number) {
    //   return environment.base_url + BaseEndpoint.API_VERSION_1 + '/products/' + id;
    // },
    // DELETE(id: number) {
    //   return environment.base_url + BaseEndpoint.API_VERSION_1 + '/products/' + id;
    // }
  };

}


