import {Injectable} from '@angular/core';
import {Observable} from "rxjs";
import {HttpClient, HttpErrorResponse, HttpHeaders} from "@angular/common/http";
import {LocalStorageService} from "../../../../../services/storage/localstorage.service";
import {environment} from "../../../../../../environments/environment";
import {AuthEndpoint} from "../auth.endpoint";
import {IAuth} from "../models/auth.model";
import {EventBusService} from "../../../../../services/eventbus/event-bus.service";
import {EventKey} from "../../../../../services/eventbus/event.key";
import {IResetPassword} from "../models/reset-password.model";
import {SubscriptionContainerService} from "../../../../../base/services/subscription-container.service";

@Injectable({
  providedIn: 'root'
})
export class AuthService {

  constructor(
    private http: HttpClient,
    private eventBus: EventBusService,
    protected subContainer: SubscriptionContainerService
  ) {
  }

  // loginCount = 0;

  login(key: string, username: string, password: string) {
    const loginUrl: string = this.getLoginUrl(username, password);
    const userAuth: Observable<IAuth> = this.http.post<any>(loginUrl, null);
    userAuth.subscribe((auth: IAuth) => {
      this.setAuth(auth)
      this.eventBus.publish(key, auth);
    }, error1 => {
      if (error1.status >= 500 || error1.status == 0) {
        this.eventBus.publish(key + ':error:1', error1)
      } else {
        this.eventBus.publish(key + ':error:2', error1)
      }
    });
  }

  setAuth(auth: IAuth) {
    LocalStorageService.putAuth(auth)
  }

  isAuthenticated(): boolean {
    return !!LocalStorageService.retrieve(LocalStorageService.KEYS.accessToken);
  }

  logout(): string {
    let key = this.globalKey(EventKey.AUTH.LOGOUT)
    if (this.isAuthenticated()) {
      LocalStorageService.clear();
      this.eventBus.publish(key, null)
    }
    this.subContainer.disposeNonGlobal()
    location.reload()
    console.log("Logged out! Disposing non-global subscriptions..")
    console.log(Array.from(this.subContainer.getKeys().keys()))
    return key
  }

  protected globalKey(key: string): string {
    return 'global:' + key
  }

  getAuth(): IAuth {
    return LocalStorageService.getAuth();
  }

  getFirstName(): string {
    if (!this.isAuthenticated()) return ''
    const splitted = this.getAuth().name.split(' ')
    if (splitted.length < 1) return ''
    return splitted[0]
  }

  getAccessToken(): string {
    return LocalStorageService.retrieve(LocalStorageService.KEYS.accessToken) as string;
  }

  getRefreshToken(): string {
    return LocalStorageService.retrieve(LocalStorageService.KEYS.refreshToken) as string;
  }


  getLoginUrl(username: string, password: string): string {
    return AuthEndpoint.AUTH.LOGIN({
      'grant_type': 'password',
      'client_id': environment.client_id,
      'client_secret': environment.client_secret,
      'username': username,
      'password': password
    });
  }

  getRefreshTokenUrl(): string {
    return AuthEndpoint.AUTH.REFRESH_TOKEN({
      'grant_type': 'refresh_token',
      'client_id': environment.client_id,
      'client_secret': environment.client_secret,
      'refresh_token': this.getRefreshToken()
    });
  }

  refreshToken$ = this.http.post<IAuth>(this.getRefreshTokenUrl(), null);

  refreshToken() {
    this.refreshToken$.subscribe((auth: IAuth) => {
      LocalStorageService.putAuth(auth);
    }, err => {
      this.logout();
    });
  }

  getAuthHeaders(): HttpHeaders {
    return new HttpHeaders({
      'Authorization': 'Bearer ' + this.getAccessToken()
    });
  }

  getAuthHeadersFromToken(token: string): HttpHeaders {
    return new HttpHeaders({
      'Authorization': 'Bearer ' + token
    });
  }

  requestPasswordResetToken(key: string, username: string) {
    this.http.get<IResetPassword>(AuthEndpoint.RESET_PASSWORD.REQUEST_TOKEN({username: username}))
      .subscribe((rp: IResetPassword) => {
        this.eventBus.publish(key, rp)
      }, (error: HttpErrorResponse) => {
        this.eventBus.publish(EventKey.RESET_PASSWORD.RESET_PASSWORD_ERROR, error)
      })
  }

  resetPassword(
    key: string,
    token: string,
    username: string,
    password: string
  ) {
    this.http.post(AuthEndpoint.RESET_PASSWORD.REQUEST_TOKEN({
      token: token,
      username: username,
      password: password
    }), null)
      .subscribe((response: any) => {
        this.eventBus.publish(key, response)
      }, (error: HttpErrorResponse) => {
        this.eventBus.publish(key+'error', error)
      })
  }
}
