import {Injectable} from '@angular/core';
import {HttpErrorResponse} from "@angular/common/http";
import {AuthService} from "../../modules/common/modules/auth/services/auth.service";
import {NotifierService} from "../../services/notifier/notifier.service";
import {CommonBase} from "../common/base.common";

@Injectable({
  providedIn: 'root'
})
export class BaseService extends CommonBase{

  constructor(
    protected authService: AuthService,
    protected notifier: NotifierService
  ) {
    super();
  }

  handleError(err: HttpErrorResponse) {
    if (err.status === 401 || err.status === 0) {
      this.authService.refreshToken();
    } else if (err.status === 400) {
      // do nothing
      this.notifier.warning(err.error.message, err.error.status);
    } else if (err.status > 400 && err.status < 500) {
      // do nothing
    } else if (err.status >= 500) {
      this.notifier.error('', "Internal Server Error!");
    } else {
      this.authService.logout();
    }

  }

}
