export class StringUtil {

  static takeOnly(str: string | null | undefined, length: number): string {
    if (str == null) str = ''
    return str.substr(0, Math.min(length, str.length))
  }

  static firstWord(str: string | null | undefined): string {
    if (str == null) str = ''
    let slices: string[] = str.split(' ')
    if (slices.length > 0) return slices[0]
    return ''
  }
}
