import {HttpErrorResponse, HttpEvent, HttpHandler, HttpInterceptor, HttpRequest} from "@angular/common/http";
import {Observable} from "rxjs";
import {catchError, map} from "rxjs/operators";
import {Injectable} from "@angular/core";
import {AuthService} from "../services/auth.service";
import {Router} from "@angular/router";

@Injectable()
export class AuthErrorInterceptor implements HttpInterceptor {
  tryCount: number = 0

  constructor(private authService: AuthService,
              private router: Router) {
  }

  intercept(request: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
    // return next.handle(req)
    let token = this.authService.getAccessToken()
    if (token === null || token.trim().length === 0 || request.method === 'OPTIONS')
      return next.handle(request);
    return next.handle(this.applyCredentials(request, token))
      .pipe(
        catchError((error: HttpErrorResponse) => {

          if (!AuthErrorInterceptor.isAuthError(error)) {
            console.log('Not auth error. throwing it as it is.')
            throw error;
          } else {
            console.log('Looks like auth error! Refreshing token..')
            this.authService.refreshToken$.pipe(map(auth => {
              token = auth.access_token
              this.authService.setAuth(auth)
              console.log('Token refreshed. ')
              // location.reload()
            })).subscribe(value => {
            },error=>{
              this.navigateByUrl("/login",(url)=>{
                this.authService.logout()
              })
            })

            return next.handle(this.applyCredentials(request, token));
          }

        })
      )
  }

  navigateByUrl(navUrl: string, then: (value: boolean) => void) {
    if (navUrl != null)
      this.router.navigateByUrl(navUrl).then(r => then(r))
  }

  private static isAuthError(error: any): boolean {
    return error instanceof HttpErrorResponse && (error.status === 401 || error.status === 0);
  }

  private applyCredentials(req: HttpRequest<any>, token: string): HttpRequest<any> {
    return req.clone({headers: this.authService.getAuthHeadersFromToken(token)});
  }
}
