import {Injectable} from '@angular/core';
import {BaseService} from "../../../base/services/base.service";
import {AuthService} from "../../common/modules/auth/services/auth.service";
import {NotifierService} from "../../../services/notifier/notifier.service";
import {HttpClient, HttpErrorResponse} from "@angular/common/http";
import {WebAppEndpoint} from "../web-app.endpoint";
import {ILeaderboard} from "../models/leaderboard/leaderboard.model";
import {EventKey} from "../../../services/eventbus/event.key";
import {EventBusService} from "../../../services/eventbus/event-bus.service";
import {IRedeem, IRedeemReq} from "../models/leaderboard/redeem.model";
import {IParams} from "../../../base/endpoints/iparams";
import {IPage} from "../../../base/models/IPage";
import {IAchievement} from "../models/leaderboard/achievement.model";

@Injectable({
  providedIn: 'root'
})
export class LeaderboardService extends BaseService {

  constructor(
    authService: AuthService,
    notifier: NotifierService,
    private http: HttpClient,
    private eventBus: EventBusService
  ) {
    super(authService, notifier)
  }

  fetchLeaderboard(key: string, username: string) {
    this.http.get<ILeaderboard>(WebAppEndpoint.LEADERBOARDS.FETCH_LEADERBOARD(username))
      .subscribe((l: ILeaderboard) => {
        this.eventBus.publish(key, l)
      }, (error: HttpErrorResponse) => {
        this.eventBus.publish(this.getErrorKey(key), error)
      })
  }

  redeem(key: string, redeem: IRedeemReq) {
    this.http.post<IRedeem>(WebAppEndpoint.LEADERBOARDS.REDEEM(), redeem)
      .subscribe((redeem: IRedeem) => {
        this.eventBus.publish(key, redeem)
      }, (error: HttpErrorResponse) => {
        this.eventBus.publish(this.getErrorKey(key), error)
      })
  }

  fetchRecentAchievements(key: string, params: IParams) {
    this.http.get<IPage<IAchievement>>(WebAppEndpoint.LEADERBOARDS.FETCH_RECENT_ACHIEVEMENTS(params))
      .subscribe((achievements: IPage<IAchievement>) => {
        this.eventBus.publish(key, achievements)
      }, (error: HttpErrorResponse) => {
        this.eventBus.publish(this.getErrorKey(key), error)
      })
  }

}
