import {AbstractControl, FormControl, ValidationErrors} from "@angular/forms";

export class ValidationUtil {

  static isInvalidInput(formControl: AbstractControl): boolean{
    return formControl.invalid && (formControl.touched || formControl.dirty)
  }

  static getFormError(formControl: AbstractControl, validationName: string): any{
    return formControl.errors?.[validationName]
  }

}
