import {Injectable} from '@angular/core';
import {MatSnackBar} from "@angular/material/snack-bar";
import {IParams} from "../../base/endpoints/iparams";
import {Router} from "@angular/router";

@Injectable({
  providedIn: 'root'
})
export class NotifierService {

  constructor(private snackbar: MatSnackBar,
              private router: Router) {
  }

  info(title: string, message: string) {
    this.snackbar.open(message, '', {
      duration: 2000,
      horizontalPosition: 'center',
      verticalPosition: 'top',
      announcementMessage: message,
      panelClass: ['snackbar-info']
    })
  }

  infoWithDuration(title: string, message: string, duration: number) {
    this.snackbar.open(message, '', {
      duration: duration,
      horizontalPosition: 'center',
      verticalPosition: 'top',
      announcementMessage: message,
      panelClass: ['snackbar-info']
    })
  }

  infoWithDurationAndAction(
    title: string,
    message: string,
    duration: number,
    param: IParams,
    action: () => void
  ) {
    let snackbarRef = this.snackbar.open(message, param['action'], {
      duration: duration,
      horizontalPosition: 'center',
      verticalPosition: 'top',
      announcementMessage: message,
      panelClass: ['snackbar-info']
    })
    snackbarRef.onAction().subscribe(value => {
      action()
    })
  }

  infoWithAction(title: string, message: string, param: IParams) {
    let snackbarRef = this.snackbar.open(message, param['action'], {
      duration: 3000,
      horizontalPosition: 'center',
      verticalPosition: 'top',
      announcementMessage: message,
      panelClass: ['snackbar-info']
    })
    let s = snackbarRef.onAction().subscribe(value => {
      this.router.navigate(param['route'])
      s.unsubscribe()
    })
  }

  success(title: string, message: string) {
    this.snackbar.open(message, '', {
      duration: 2000,
      horizontalPosition: 'center',
      verticalPosition: 'top',
      announcementMessage: message,
      panelClass: ['snackbar-success']
    })
  }


  successWithAction(title: string, message: string, param: IParams) {
    let snackbarRef = this.snackbar.open(message, param['action'], {
      duration: 3000,
      horizontalPosition: 'center',
      verticalPosition: 'top',
      announcementMessage: message,
      panelClass: ['snackbar-success']
    })
    let s = snackbarRef.onAction().subscribe(value => {
      this.router.navigate(param['route'])
      s.unsubscribe()
    })
  }

  warning(title: string, message: string) {
    this.snackbar.open(message, '', {
      duration: 2000,
      horizontalPosition: 'center',
      verticalPosition: 'top',
      announcementMessage: message,
      panelClass: ['snackbar-warning']
    })
  }

  warningWithAction(title: string, message: string, param: IParams) {
    let snackbarRef = this.snackbar.open(message, param['action'], {
      duration: 3000,
      horizontalPosition: 'center',
      verticalPosition: 'top',
      announcementMessage: message,
      panelClass: ['snackbar-warning']
    })
    let s = snackbarRef.onAction().subscribe(value => {
      this.router.navigate(param['route'])
      s.unsubscribe()
    })
  }

  error(title: string, message: string) {
    this.snackbar.open(message, '', {
      duration: 2000,
      horizontalPosition: 'center',
      verticalPosition: 'top',
      announcementMessage: message,
      panelClass: ['snackbar-error']
    })
  }

  errorWithAction(title: string, message: string, param: IParams) {
    let snackbarRef = this.snackbar.open(message, param['action'], {
      duration: 3000,
      horizontalPosition: 'center',
      verticalPosition: 'top',
      announcementMessage: message,
      panelClass: ['snackbar-error']
    })
    let s = snackbarRef.onAction().subscribe(value => {
      this.router.navigate(param['route'])
      s.unsubscribe()
    })
  }

  log(obj: any) {
    console.log(obj)
  }

}
