import {Injectable} from '@angular/core';
import {BaseService} from "../../../base/services/base.service";
import {AuthService} from "../../common/modules/auth/services/auth.service";
import {NotifierService} from "../../../services/notifier/notifier.service";
import {HttpClient, HttpErrorResponse} from "@angular/common/http";
import {EventBusService} from "../../../services/eventbus/event-bus.service";
import {WebAppEndpoint} from "../web-app.endpoint";
import {IWallet} from "../models/wallet/wallet.model";
import {EventKey} from "../../../services/eventbus/event.key";

@Injectable({
  providedIn: 'root'
})
export class WalletService extends BaseService {

  constructor(authService: AuthService,
              notifier: NotifierService,
              private http: HttpClient,
              private eventBus: EventBusService) {
    super(authService, notifier);
  }


  fetchMyWallet(key: string) {
    this.http.get<IWallet>(WebAppEndpoint.WALLET.FETCH_MY_WALLET())
      .subscribe((wallet: IWallet) => {
        this.eventBus.publish(key, wallet)
      }, (error: HttpErrorResponse) => {
        this.eventBus.publish(key, error)
      })
  }
}
