import {Injectable} from '@angular/core';
import {BaseService} from "../../../base/services/base.service";
import {AuthService} from "../../common/modules/auth/services/auth.service";
import {NotifierService} from "../../../services/notifier/notifier.service";
import {IParams} from "../../../base/endpoints/iparams";
import {HttpClient, HttpErrorResponse, HttpResponse} from "@angular/common/http";
import {IPage} from "../../../base/models/IPage";
import {INotification} from "../models/notifications/notification.model";
import {WebAppEndpoint} from "../web-app.endpoint";
import {EventBusService} from "../../../services/eventbus/event-bus.service";

@Injectable({
  providedIn: 'root'
})
export class NotificationService extends BaseService {


  constructor(
    authService: AuthService,
    notifier: NotifierService,
    private http: HttpClient,
    private eventBus: EventBusService
  ) {
    super(authService, notifier);
  }


  fetchMyNotifications(key: string, params: IParams) {
    this.http.get<IPage<INotification>>(WebAppEndpoint.NOTIFICATIONS.FETCH_MY_NOTIFICATIONS(params))
      .subscribe((notifications: IPage<INotification>) => {
        this.eventBus.publish(key, notifications)
      }, (error: HttpErrorResponse) => {
        this.eventBus.publish(this.getErrorKey(key), error)
      })
  }

  markRead(key: string, countKey: string, notificationId: number, read: boolean) {
    this.http.post(WebAppEndpoint.NOTIFICATIONS.MARK_READ({id: notificationId, read: read}), null)
      .subscribe(res => {
        this.eventBus.publish(key, res)
        this.eventBus.publish(countKey, res) // trigger notification count call
      }, (err: HttpErrorResponse) => {
        this.eventBus.publish(this.getErrorKey(key), err)
      })
  }
  countUnread(key: string) {
    this.http.get<number>(WebAppEndpoint.NOTIFICATIONS.COUNT_UNREAD({}))
      .subscribe(res => {
        this.eventBus.publish(key, res)
      }, (err: HttpErrorResponse) => {
        this.eventBus.publish(this.getErrorKey(key), err)
      })
  }

}
