import {Injectable} from '@angular/core';
import {BaseService} from "../../../../../base/services/base.service";
import {AuthService} from "./auth.service";
import {NotifierService} from "../../../../../services/notifier/notifier.service";
import {HttpClient, HttpErrorResponse} from "@angular/common/http";
import {EventBusService} from "../../../../../services/eventbus/event-bus.service";
import {WebAppEndpoint} from "../../../../webapp/web-app.endpoint";

@Injectable({
  providedIn: 'root'
})
export class UserService extends BaseService {

  constructor(
    authService: AuthService,
    notifier: NotifierService,
    private http: HttpClient,
    private eventBus: EventBusService
  ) {
    super(authService, notifier)

  }

  deleteAccount(key: string): void {
    this.http.delete(WebAppEndpoint.USER.DELETE_ME())
      .subscribe(res => {
        this.eventBus.publish(key, res)
      }, (error: HttpErrorResponse) => {
        this.eventBus.publish(this.getErrorKey(key), error)
      })
  }

}
